<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: 'Courier New', monospace;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 20px;
    gap: 20px;
  }

  h1 {
    font-size: 1.6rem;
    letter-spacing: 0.2em;
    color: #7fff7f;
    text-shadow: 0 0 12px #00ff0055;
  }

  #life {
    width: 500px;
    height: 500px;
    cursor: crosshair;
    border: 2px solid #2a2a2a;
    border-radius: 4px;
    box-shadow: 0 0 30px #00ff0022, 0 0 60px #00ff0011;
    display: block;
  }

  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    background: #1a1a1a;
    color: #7fff7f;
    border: 1px solid #3a3a3a;
    padding: 10px 22px;
    font-family: 'Courier New', monospace;
    font-size: 0.9rem;
    letter-spacing: 0.1em;
    border-radius: 4px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, box-shadow 0.15s;
  }

  button:hover {
    background: #222;
    border-color: #7fff7f;
    box-shadow: 0 0 10px #7fff7f44;
  }

  button:active {
    background: #7fff7f22;
  }

  button.active {
    background: #7fff7f22;
    border-color: #7fff7f;
    box-shadow: 0 0 14px #7fff7f66;
    color: #afffaf;
  }

  .info {
    font-size: 0.75rem;
    color: #555;
    letter-spacing: 0.05em;
  }

  #gen-counter {
    color: #4a9;
  }
</style>
</head>
<body>
<h1>GAME OF LIFE</h1>

<canvas id="life" width="500" height="500"></canvas>

<div class="controls">
  <button id="step">STEP</button>
  <button id="play">PLAY</button>
  <button id="random">RANDOM</button>
  <button id="clear">CLEAR</button>
</div>

<div class="info">Generation: <span id="gen-counter">0</span></div>

<script>
(function() {
  const COLS = 50;
  const ROWS = 50;
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;
  const CELL_W = W / COLS;
  const CELL_H = H / ROWS;

  let grid = new Uint8Array(COLS * ROWS);
  let generation = 0;
  let playing = false;
  let animId = null;
  let lastTime = 0;
  const INTERVAL = 100;

  function idx(x, y) { return y * COLS + x; }

  function getCell(x, y) {
    if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return 0;
    return grid[idx(x, y)];
  }

  function setCell(x, y, v) {
    if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return;
    grid[idx(x, y)] = v ? 1 : 0;
    draw();
  }

  function stepGen() {
    const next = new Uint8Array(COLS * ROWS);
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        let n = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            n += getCell(x + dx, y + dy);
          }
        }
        const alive = grid[idx(x, y)];
        if (alive) {
          next[idx(x, y)] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          next[idx(x, y)] = (n === 3) ? 1 : 0;
        }
      }
    }
    grid = next;
    generation++;
    document.getElementById('gen-counter').textContent = generation;
    draw();
  }

  function clearGrid() {
    grid = new Uint8Array(COLS * ROWS);
    generation = 0;
    document.getElementById('gen-counter').textContent = 0;
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.3 ? 1 : 0;
    }
    generation = 0;
    document.getElementById('gen-counter').textContent = 0;
    draw();
  }

  function draw() {
    ctx.fillStyle = '#0d0d0d';
    ctx.fillRect(0, 0, W, H);

    // Grid lines
    ctx.strokeStyle = '#1a1a1a';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= COLS; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL_W, 0);
      ctx.lineTo(x * CELL_W, H);
      ctx.stroke();
    }
    for (let y = 0; y <= ROWS; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL_H);
      ctx.lineTo(W, y * CELL_H);
      ctx.stroke();
    }

    // Cells
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        if (grid[idx(x, y)]) {
          const px = x * CELL_W;
          const py = y * CELL_H;
          // Glow effect
          const grad = ctx.createRadialGradient(
            px + CELL_W / 2, py + CELL_H / 2, 0,
            px + CELL_W / 2, py + CELL_H / 2, CELL_W * 0.8
          );
          grad.addColorStop(0, '#afffaf');
          grad.addColorStop(0.5, '#4fc74f');
          grad.addColorStop(1, '#1a5c1a');
          ctx.fillStyle = grad;
          ctx.fillRect(px + 1, py + 1, CELL_W - 2, CELL_H - 2);
        }
      }
    }
  }

  // Auto-play loop
  function loop(ts) {
    if (!playing) return;
    if (ts - lastTime >= INTERVAL) {
      stepGen();
      lastTime = ts;
    }
    animId = requestAnimationFrame(loop);
  }

  function togglePlay() {
    playing = !playing;
    const btn = document.getElementById('play');
    if (playing) {
      btn.textContent = 'PAUSE';
      btn.classList.add('active');
      lastTime = performance.now();
      animId = requestAnimationFrame(loop);
    } else {
      btn.textContent = 'PLAY';
      btn.classList.remove('active');
      if (animId) cancelAnimationFrame(animId);
    }
  }

  // Mouse/touch interaction
  let painting = false;
  let paintValue = 1;

  function canvasCoords(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = COLS / rect.width;
    const scaleY = ROWS / rect.height;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const x = Math.floor((clientX - rect.left) * scaleX);
    const y = Math.floor((clientY - rect.top) * scaleY);
    return { x, y };
  }

  canvas.addEventListener('mousedown', e => {
    painting = true;
    const { x, y } = canvasCoords(e);
    paintValue = getCell(x, y) ? 0 : 1;
    setCell(x, y, paintValue);
  });

  canvas.addEventListener('mousemove', e => {
    if (!painting) return;
    const { x, y } = canvasCoords(e);
    setCell(x, y, paintValue);
  });

  window.addEventListener('mouseup', () => { painting = false; });

  canvas.addEventListener('touchstart', e => {
    e.preventDefault();
    painting = true;
    const { x, y } = canvasCoords(e);
    paintValue = getCell(x, y) ? 0 : 1;
    setCell(x, y, paintValue);
  }, { passive: false });

  canvas.addEventListener('touchmove', e => {
    e.preventDefault();
    if (!painting) return;
    const { x, y } = canvasCoords(e);
    setCell(x, y, paintValue);
  }, { passive: false });

  window.addEventListener('touchend', () => { painting = false; });

  // Button bindings
  document.getElementById('step').addEventListener('click', () => {
    if (playing) togglePlay();
    stepGen();
  });
  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', randomize);
  document.getElementById('clear').addEventListener('click', clearGrid);

  // Expose API
  window.life = {
    get w() { return COLS; },
    get h() { return ROWS; },
    get(x, y) { return getCell(x, y); },
    set(x, y, v) { setCell(x, y, v); },
    step() { stepGen(); },
    clear() { clearGrid(); }
  };

  // Initial draw
  draw();
})();
</script>
</body>
</html>
